PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?club1 ?inception1 ?club2 ?inception2 WHERE {
  {
    ?player1 wdt:P748 wd:Q4585782 ; wdt:P1352 1 ; wdt:P1505 ?club1 .
    ?club1 wdt:P571 ?inception1 .
  } UNION {
    ?player2 wdt:P748 wd:Q4585782 ; wdt:P1352 6 ; wdt:P1505 ?club2 .
    ?club2 wdt:P571 ?inception2 .
  }
}

